import json
from elasticsearch import Elasticsearch

def validate_script(script):
    try:
        # Validate script syntax using the Elasticsearch client's scripting API
        es = Elasticsearch()
        es.indices.validate_query(index='my_index', query={'script': {'source': script}})
    except Exception as e:
        print(f"Invalid script: {e}")
        return False

    return True

def execute_script(es, index, script):
    try:
        # Execute the script using the Elasticsearch client's scripting API
        result = es.search(index=index, body={
            'query': {
                'script': {'source': script}
            }
        })
        
        print(result)
    except Exception as e:
        print(f"Error executing script: {e}")

def main():
    with open('req.json') as f:
        req = json.load(f)

    if not validate_script(req['script']):
        return

    es = Elasticsearch()
    
    # Check if inline scripts are enabled in the cluster config
    if not es.cluster.health(wait_for_status='yellow')['initializing_shards'] == 0 and not es.cluster.health()['persistent']['cluster']['routing']['script']['inline']:
        print("Inline scripts are not enabled. Please enable them in your cluster config.")
        return

    execute_script(es, 'my_index', req['script'])

if __name__ == "__main__":
    main()